import { createItem, deleteItem, readItems, updateItem } from '@directus/sdk'
import { directus } from '@/lib/directus'
import type {
  CrmAiModelConfig,
  Buyer,
  CrmDepartment,
  CrmEmailMessage,
  CrmIgnoreRule,
  CrmLicensorApprovalThread,
  CrmMeetingNote,
  CrmNote,
  CrmOpportunity,
  CrmTask,
  Retailer,
} from '@/lib/types'

export async function fetchOpportunities(): Promise<CrmOpportunity[]> {
  return directus.request(
    readItems('crm_opportunity', {
      fields: [
        'id',
        'name',
        'amount',
        'close_date',
        'stage',
        'program_type',
        'season_year',
        'division',
        'production_po_number',
        'sales_order_number',
        'hard_delivery_date',
        'ai_summary',
        'ai_state',
        { retailer: ['id', 'name', 'customer_status'] },
        { contact: ['id', 'name', 'email'] },
        { department: ['id', 'name'] },
        { factory: ['id', 'name'] },
        { project: ['id', 'title'] },
      ],
      sort: ['stage', 'name'],
      limit: -1,
    }),
